import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useParams } from "react-router-dom";

export default function SlotList() {
  const { id } = useParams();
  const [slots, setSlots] = useState([]);
  const [userBookingCount, setUserBookingCount] = useState(0);

  const load = async () => {
    const slotRes = await axios.get(`/slots/${id}`);
    setSlots(slotRes.data);

    // Fetch user's bookings to count them for this lot
    const bookingRes = await axios.get("/bookings/my");
    const myBookingsInLot = bookingRes.data.filter(
      (b) => b.slotId && b.slotId.parkingLotId === id
    );
    setUserBookingCount(myBookingsInLot.length);
  };

  useEffect(() => {
    load();
  }, [id]);

  const book = async (slotId) => {
    if (userBookingCount >= 2) {
      alert("A user can book only 2 slots in a lot");
      return;
    }
    try {
      await axios.post("/bookings", { slotId });
      load();
    } catch (err) {
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  // Helper Component for consistent slot sizing
  const SlotItem = ({ s, userBookingCount, book }) => (
    <div
      className={`slot-item ${s.isBooked ? "slot-booked" : (userBookingCount >= 2 ? "slot-disabled" : "slot-free")}`}
      onClick={() => !s.isBooked && (userBookingCount < 2 ? book(s._id) : alert("A user can book only 2 slots in a lot"))}
      style={{
        ...(userBookingCount >= 2 && !s.isBooked ? { opacity: 0.6, cursor: "not-allowed" } : {}),
        border: '2px dashed #ccc',
        borderRadius: '5px',
        padding: '10px',
        textAlign: 'center',
        backgroundColor: s.isBooked ? '#ffebee' : '#e8f5e9',
        position: 'relative',
        minWidth: '60px'
      }}
    >
      <h4 style={{ margin: '0 0 5px 0', fontSize: '1em' }}>{s.slotNumber.split("-")[1] || s.slotNumber}</h4>
      <span style={{ fontSize: '0.7em', color: s.isBooked ? '#c62828' : '#2e7d32' }}>
        {s.isBooked ? "Reserved" : "Reserve"}
      </span>
    </div>
  );

  // --- LAYOUT COMPONENTS ---

  const AirportLayout = ({ slots, userBookingCount, book }) => (
    <div style={{ display: 'flex', gap: '40px', justifyContent: 'center', flexWrap: 'wrap' }}>
      {["T1", "T2"].map(term => (
        <div key={term} style={{ background: '#f8f9fa', padding: '15px', borderRadius: '8px', border: '1px solid #ddd' }}>
          <h3 style={{ borderBottom: '2px solid #007bff', paddingBottom: '5px', color: '#0056b3' }}>Terminal {term.slice(1)} Parking</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '10px' }}>
            {slots.filter(s => s.slotNumber.startsWith(term)).map(s => (
              <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const MallLayout = ({ slots, userBookingCount, book }) => (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '30px' }}>
      {["P1", "P2", "P3"].map(level => (
        <div key={level}>
          <div style={{ background: '#6c757d', color: 'white', padding: '5px 15px', borderRadius: '4px 4px 0 0', fontWeight: 'bold' }}>
            Level {level.slice(1)}
          </div>
          <div style={{ border: '2px solid #6c757d', padding: '15px', borderRadius: '0 0 4px 4px', display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
            {slots.filter(s => s.slotNumber.startsWith(level)).map(s => (
              <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const StadiumLayout = ({ slots, userBookingCount, book }) => (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px', maxWidth: '800px', margin: '0 auto' }}>
      {["North", "South", "East", "West"].map(gate => (
        <div key={gate} style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#28a745' }}>{gate} Gate Stand</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '8px' }}>
            {slots.filter(s => s.slotNumber.startsWith(gate)).map(s => (
              <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const HospitalLayout = ({ slots, userBookingCount, book }) => (
    <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr', gap: '20px' }}>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        <div style={{ background: '#ffebee', padding: '10px', borderRadius: '4px', border: '1px solid #ffcdd2' }}>
          <h4 style={{ color: '#c62828', marginTop: 0 }}>🚑 Emergency</h4>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '5px' }}>
            {slots.filter(s => s.slotNumber.startsWith("Emerg")).map(s => (
              <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />
            ))}
          </div>
        </div>
        <div style={{ background: '#e3f2fd', padding: '10px', borderRadius: '4px', border: '1px solid #bbdefb' }}>
          <h4 style={{ color: '#1565c0', marginTop: 0 }}>👨‍⚕️ Staff Only</h4>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '5px' }}>
            {slots.filter(s => s.slotNumber.startsWith("Staff")).map(s => (
              <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />
            ))}
          </div>
        </div>
      </div>

      <div>
        <h3 style={{ borderBottom: '2px solid #ddd' }}>Visitor Parking</h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(60px, 1fr))', gap: '10px' }}>
          {slots.filter(s => s.slotNumber.startsWith("Visitor")).map(s => (
            <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />
          ))}
        </div>
      </div>
    </div>
  );

  const CampusLayout = ({ slots, userBookingCount, book }) => (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: '20px', maxWidth: '800px', margin: '0 auto' }}>
      <div style={{ gridColumn: '1 / -1', borderBottom: '4px solid #333', paddingBottom: '10px' }}>
        <h3 style={{ textAlign: 'center', margin: '0 0 10px 0' }}>Top Section</h3>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px', justifyContent: 'center' }}>
          {slots.filter(s => s.slotNumber.startsWith("Top-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
        </div>
      </div>
      <div style={{ gridColumn: '1 / 2', borderRight: '4px dashed #ccc', paddingRight: '10px' }}>
        <h4 style={{ textAlign: 'center' }}>West Wing</h4>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          {slots.filter(s => s.slotNumber.startsWith("Left-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
        </div>
      </div>
      <div style={{ gridColumn: '2 / 4', display: 'flex', justifyContent: 'center', gap: '40px' }}>
        <div>
          <h4 style={{ textAlign: 'center' }}>Central A</h4>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {slots.filter(s => s.slotNumber.startsWith("CenterA-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
          </div>
        </div>
        <div style={{ width: '40px', background: '#e0e0e0', display: 'flex', alignItems: 'center', justifyContent: 'center', writingMode: 'vertical-rl', borderRadius: '5px' }}>DRIVING LANE</div>
        <div>
          <h4 style={{ textAlign: 'center' }}>Central B</h4>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {slots.filter(s => s.slotNumber.startsWith("CenterB-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
          </div>
        </div>
      </div>
      <div style={{ gridColumn: '4 / 5', borderLeft: '4px dashed #ccc', paddingLeft: '10px' }}>
        <h4 style={{ textAlign: 'center' }}>East Wing</h4>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          {slots.filter(s => s.slotNumber.startsWith("Right-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
        </div>
      </div>
    </div>
  );

  const StandardLayout = ({ slots, userBookingCount, book }) => (
    <div className="parking-layout" style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {Object.entries(slots.reduce((groups, slot) => {
        const row = slot.slotNumber.split("-")[0];
        if (!groups[row]) groups[row] = [];
        groups[row].push(slot);
        return groups;
      }, {})).sort().map(([row, rowSlots]) => (
        <div key={row} className="parking-row">
          <div style={{ fontWeight: 'bold', marginBottom: '5px', color: '#555', borderBottom: '2px solid #ddd', paddingBottom: '5px' }}>Row {row}</div>
          <div className="slot-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '10px', marginBottom: '10px' }}>
            {rowSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
          </div>
          <div className="driving-lane" style={{ height: '40px', background: '#555', borderRadius: '5px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '0.8em', letterSpacing: '2px', opacity: 0.8 }}>⬇⬆ DRIVING LANE ⬇⬆</div>
        </div>
      ))}
    </div>
  );

  return (
    <div className="container">
      <h2>Select a Slot</h2>
      {userBookingCount >= 2 && (
        <div style={{ color: "#d9534f", background: "#f2dede", padding: "10px", borderRadius: "4px", marginBottom: "15px", fontWeight: "bold", textAlign: "center", border: "1px solid #ebccd1" }}>
          ⚠️ A user can book only 2 slots in a lot
        </div>
      )}

      {/* RENDER LAYOUT BASED ON DATA */}
      <div className="parking-layout" style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        {slots.some(s => s.slotNumber.startsWith("T1-")) ? <AirportLayout slots={slots} userBookingCount={userBookingCount} book={book} /> :
          slots.some(s => s.slotNumber.startsWith("P1-")) ? <MallLayout slots={slots} userBookingCount={userBookingCount} book={book} /> :
            slots.some(s => s.slotNumber.startsWith("North-")) ? <StadiumLayout slots={slots} userBookingCount={userBookingCount} book={book} /> :
              slots.some(s => s.slotNumber.startsWith("Emerg")) ? <HospitalLayout slots={slots} userBookingCount={userBookingCount} book={book} /> :
                slots.some(s => s.slotNumber.startsWith("Top-")) ? <CampusLayout slots={slots} userBookingCount={userBookingCount} book={book} /> :
                  <StandardLayout slots={slots} userBookingCount={userBookingCount} book={book} />}
      </div>
    </div>
  );
}
